/// An individual SSE event
///
/// Represents a single Server-Sent Event to be sent to a connected client.
/// Events can have an optional type, ID, and retry timeout for advanced scenarios.
///
/// # Fields
///
/// * `event_type` - Optional event type string (used for client-side event filtering)
/// * `data` - JSON data payload to send to the client
/// * `id` - Optional event ID (clients can use this to resume after disconnect)
/// * `retry` - Optional retry timeout in milliseconds (tells client when to reconnect)
///
/// # SSE Format
///
/// Events are serialized to the following text format:
/// ```text
/// event: event_type
/// data: {"json":"value"}
/// id: event-123
/// retry: 3000
/// ```
#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
#[napi(object, js_name = "SseEvent")]
pub struct JsSseEvent {
    /// Event type (optional)
    #[napi(js_name = "eventType")]
    #[serde(rename = "eventType")]
    pub event_type: Option<String>,
    /// Event data (JSON value)
    pub data: serde_json::Value,
    /// Event ID (optional, for client-side reconnection)
    pub id: Option<String>,
    /// Retry timeout in milliseconds (optional)
    pub retry: Option<i64>,
}

/// Set the event ID for client-side reconnection support
///
/// Sets an ID that clients can use to resume from this point if they disconnect.
/// The client sends this ID back in the `Last-Event-ID` header when reconnecting.
///
/// # Arguments
/// * `id` - Unique identifier for this event
///
/// # Example
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "sseEventWithId")]
pub fn sse_event_with_id(cfg: JsSseEvent, id: String) -> napi::Result<JsSseEvent> {
    let _json =
        serde_json::to_string(&cfg).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _core: spikard::SseEvent =
        serde_json::from_str(&_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _result = _core.with_id(id);
    let _out_json =
        serde_json::to_string(&_result).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    serde_json::from_str(&_out_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}
/// Set the retry timeout for client reconnection
///
/// Sets the time in milliseconds clients should wait before attempting to reconnect
/// if the connection is lost. The client browser will automatically handle reconnection.
///
/// # Arguments
/// * `retry_ms` - Retry timeout in milliseconds
///
/// # Example
#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "sseEventWithRetry")]
pub fn sse_event_with_retry(cfg: JsSseEvent, retry_ms: i64) -> napi::Result<JsSseEvent> {
    let _json =
        serde_json::to_string(&cfg).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _core: spikard::SseEvent =
        serde_json::from_str(&_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _result = _core.with_retry(retry_ms as u64);
    let _out_json =
        serde_json::to_string(&_result).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    serde_json::from_str(&_out_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}

