/// Spikard application builder.
#[derive(Clone)]
#[napi(js_name = "App")]
pub struct JsApp {
    inner: Arc<std::sync::Mutex<spikard::App>>,
}

#[napi]
impl JsApp {
    /// Register a `/graphql`-style route backed by one of Spikard's built-in
    /// async-graphql test schemas.
    ///
    /// This is a binding-friendly entry point: unlike `spikard_graphql.GraphQLHandler`,
    /// which is generic over the GraphQL root types and therefore cannot cross an FFI
    /// boundary, this method is monomorphic. Callers select a schema by name and the
    /// concrete `GraphQLHandler<Query, Mutation, Subscription>` is constructed internally
    /// and registered as an `Arc<dyn Handler>`.
    ///
    /// The built-in schemas exist to exercise Spikard's GraphQL execution path end to
    /// end (see `fixtures/graphql_schema.json`); they are not meant to be extended with
    /// application-specific fields. Hosts that need a custom GraphQL schema should build
    /// their own `GraphQLHandler` in Rust and register it via `App.route`.
    ///
    /// # Arguments
    ///
    /// * `path` - The HTTP path to serve GraphQL requests on (e.g. `/graphql`).
    /// * `method` - The HTTP method to accept (fixtures always use `POST`).
    /// * `schema_type` - One of `"query_only"`, `"query_mutation"`, or `"full"`.
    /// * `config` - Introspection/complexity/depth limits applied to the selected schema.
    ///
    /// # Errors
    ///
    /// Returns `AppError.GraphQL` if `schema_type` is not a recognized built-in schema
    /// name, and `AppError.Route` if route construction fails.
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "registerGraphqlRoute")]
    pub fn register_graphql_route(
        &self,
        path: String,
        method: JsMethod,
        schema_type: String,
        config: JsSchemaConfig,
    ) -> Result<JsApp> {
        let method_json = serde_json::to_string(&method)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let method_core: spikard::Method = serde_json::from_str(&method_json)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let config_json = serde_json::to_string(&config)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let config_core: spikard::SchemaConfig = serde_json::from_str(&config_json)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        self.inner
            .lock()
            .unwrap()
            .register_graphql_route(path, method_core, &schema_type, &config_core)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(Self {
            inner: self.inner.clone(),
        })
    }

    /// Register a `/graphql`-style route backed by an arbitrary SDL schema string, with field
    /// resolution driven by a static `response_data` JSON tree instead of hand-written Rust
    /// resolvers.
    ///
    /// This is the dynamic-schema counterpart to `App.register_graphql_route`: instead of
    /// selecting one of Spikard's built-in test schemas by name, callers supply their own SDL
    /// and a JSON tree shaped like the successful `data` payload each query should produce. Every
    /// field resolver is generic — it navigates `response_data` by field name — so
    /// argument-dependent results (e.g. `user(id: "user-42")`) must already be baked into
    /// `response_data` at the correct path. See `spikard_graphql.dynamic` for the full
    /// resolver-data encoding and field-level-error support via `config.field_errors`.
    ///
    /// # Arguments
    ///
    /// * `path` - The HTTP path to serve GraphQL requests on (e.g. `/graphql`).
    /// * `method` - The HTTP method to accept (fixtures always use `POST`).
    /// * `sdl` - The GraphQL SDL schema string (object and input-object types only).
    /// * `response_data` - JSON tree resolvers navigate by field name to produce query results.
    /// * `config` - Introspection/complexity/depth limits and field-level error injection.
    ///
    /// # Errors
    ///
    /// Returns `AppError.GraphQL` if the SDL cannot be parsed or fails dynamic-schema
    /// validation (e.g. an unsupported type kind, duplicate field names), and
    /// `AppError.Route` if route construction fails.
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "registerGraphqlSdlRoute")]
    pub fn register_graphql_sdl_route(
        &self,
        path: String,
        method: JsMethod,
        sdl: String,
        response_data: serde_json::Value,
        config: JsDynamicSchemaConfig,
    ) -> Result<JsApp> {
        let method_json = serde_json::to_string(&method)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let method_core: spikard::Method = serde_json::from_str(&method_json)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let config_json = serde_json::to_string(&config)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        let config_core: spikard::DynamicSchemaConfig = serde_json::from_str(&config_json)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        self.inner
            .lock()
            .unwrap()
            .register_graphql_sdl_route(path, method_core, &sdl, response_data, &config_core)
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(Self {
            inner: self.inner.clone(),
        })
    }

    /// Create a new application with the default server configuration.
    #[napi]
    pub fn new() -> JsApp {
        Self {
            inner: Arc::new(std::sync::Mutex::new(spikard::App::new())),
        }
    }

    #[allow(clippy::should_implement_trait)]
    #[napi]
    pub fn default() -> JsApp {
        Self {
            inner: Arc::new(std::sync::Mutex::new(spikard::App::default())),
        }
    }
}

#[napi]
impl JsApp {
    #[napi(constructor)]
    pub fn new_constructor() -> Self {
        Self {
            inner: std::sync::Arc::new(std::sync::Mutex::new(spikard::App::new())),
        }
    }
}

impl Default for JsApp {
    fn default() -> Self {
        Self::new()
    }
}

