#[allow(clippy::missing_errors_doc)]
#[napi(js_name = "problemDetailsWithInstance")]
pub fn problem_details_with_instance(cfg: JsProblemDetails, instance: String) -> napi::Result<JsProblemDetails> {
    let _json =
        serde_json::to_string(&cfg).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _core: spikard_core::ProblemDetails =
        serde_json::from_str(&_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    let _result = _core.with_instance(instance);
    let _out_json =
        serde_json::to_string(&_result).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
    serde_json::from_str(&_out_json).map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))
}
