/// Core test client for making HTTP requests to a Spikard application.
///
/// This struct wraps axum-test's TestServer and provides a language-agnostic
/// interface for making HTTP requests, sending WebSocket connections, and
/// handling Server-Sent Events. Language bindings wrap this to provide
/// native API surfaces.
#[derive(Clone)]
#[napi(js_name = "TestClient")]
pub struct JsTestClient {
    inner: Arc<spikard_http::testing::test_client::TestClient>,
}

#[napi]
impl JsTestClient {
    ///  a GraphQL query/mutation to a custom endpoint
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "graphqlAt")]
    pub async fn graphql_at(
        &self,
        endpoint: String,
        query: String,
        variables: Option<serde_json::Value>,
        operation_name: Option<String>,
    ) -> Result<JsResponseSnapshot> {
        let inner = self.inner.clone();
        let result = inner
            .graphql_at(&endpoint, &query, variables, operation_name.as_deref())
            .await
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result.into())
    }

    ///  a GraphQL query/mutation
    #[allow(clippy::missing_errors_doc)]
    #[napi]
    pub async fn graphql(
        &self,
        query: String,
        variables: Option<serde_json::Value>,
        operation_name: Option<String>,
    ) -> Result<JsResponseSnapshot> {
        let inner = self.inner.clone();
        let result = inner
            .graphql(&query, variables, operation_name.as_deref())
            .await
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result.into())
    }

    ///  a GraphQL subscription (WebSocket) to a custom endpoint.
    ///
    /// Uses the `graphql-transport-ws` protocol and captures the first `next` payload.
    /// After the first payload is received, this client sends `complete` to unsubscribe.
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "graphqlSubscriptionAt")]
    pub async fn graphql_subscription_at(
        &self,
        endpoint: String,
        query: String,
        variables: Option<serde_json::Value>,
        operation_name: Option<String>,
    ) -> Result<JsGraphQLSubscriptionSnapshot> {
        let inner = self.inner.clone();
        let result = inner
            .graphql_subscription_at(&endpoint, &query, variables, operation_name.as_deref())
            .await
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result.into())
    }

    ///  a GraphQL subscription (WebSocket).
    ///
    /// Uses `/graphql` as the default subscription endpoint.
    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "graphqlSubscription")]
    pub async fn graphql_subscription(
        &self,
        query: String,
        variables: Option<serde_json::Value>,
        operation_name: Option<String>,
    ) -> Result<JsGraphQLSubscriptionSnapshot> {
        let inner = self.inner.clone();
        let result = inner
            .graphql_subscription(&query, variables, operation_name.as_deref())
            .await
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result.into())
    }
}

