impl From<JsSecuritySchemeInfo> for spikard_http::SecuritySchemeInfo {
    fn from(val: JsSecuritySchemeInfo) -> Self {
        match val.type_tag.as_str() {
            "http" => Self::Http {
                scheme: val.scheme.unwrap_or_default(),
                bearer_format: val.bearer_format,
            },
            "apiKey" => Self::ApiKey {
                location: val.location.unwrap_or_default(),
                name: val.name.unwrap_or_default(),
            },
            _ => Self::Http {
                scheme: Default::default(),
                bearer_format: Default::default(),
            },
        }
    }
}

impl From<spikard_http::SecuritySchemeInfo> for JsSecuritySchemeInfo {
    fn from(val: spikard_http::SecuritySchemeInfo) -> Self {
        match val {
            spikard_http::SecuritySchemeInfo::Http { scheme, bearer_format } => Self {
                type_tag: "http".to_string(),
                bearer_format: bearer_format,
                location: None,
                name: None,
                scheme: Some(scheme),
            },
            spikard_http::SecuritySchemeInfo::ApiKey { location, name } => Self {
                type_tag: "apiKey".to_string(),
                bearer_format: None,
                location: Some(location),
                name: Some(name),
                scheme: None,
            },
        }
    }
}

