pub const APP_ERROR_ERROR_SERVER: &str = "Server";
pub const APP_ERROR_ERROR_DECODE: &str = "Decode";
pub const APP_ERROR_ERROR_GRAPH_Q_L: &str = "GraphQL";

/// Convert a `spikard::AppError` error to a NAPI error.
#[allow(dead_code)]
fn app_error_to_napi_err(e: spikard::AppError) -> napi::Error {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        spikard::AppError::Route(..) => napi::Error::new(napi::Status::GenericFailure, format!("[Route] {}", msg)),
        spikard::AppError::Server(..) => napi::Error::new(napi::Status::GenericFailure, format!("[Server] {}", msg)),
        spikard::AppError::Decode(..) => napi::Error::new(napi::Status::GenericFailure, format!("[Decode] {}", msg)),
        spikard::AppError::GraphQL(..) => napi::Error::new(napi::Status::GenericFailure, format!("[GraphQL] {}", msg)),
        _ => napi::Error::new(napi::Status::GenericFailure, msg),
    }
}

