#[napi]
pub struct JsGraphQLErrorInfo {
    pub status_code: u16,
    pub is_transient: bool,
    pub error_type: String,
}

#[allow(dead_code)]
fn graph_q_l_error_info(e: &spikard_graphql::error::GraphQLError) -> JsGraphQLErrorInfo {
    JsGraphQLErrorInfo {
        status_code: e.status_code(),
        is_transient: e.is_transient(),
        error_type: e.error_type().to_string(),
    }
}

#[napi]
impl JsGraphQLErrorInfo {
    /// HTTP status code for this error (0 means no associated status).
    #[napi(js_name = "statusCode")]
    pub fn status_code(&self) -> u16 {
        self.status_code
    }

    /// Returns `true` if the error is transient and a retry may succeed.
    #[napi(js_name = "isTransient")]
    pub fn is_transient(&self) -> bool {
        self.is_transient
    }

    /// Machine-readable error category string for matching and logging.
    #[napi(js_name = "errorType")]
    pub fn error_type(&self) -> String {
        self.error_type.clone()
    }
}

